css:
* { margin: 0; padding: 0; box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; }
body { background: #f7f5f2; color: #1e1b18; }
.navbar { display: flex; justify-content: space-between; align-items: center; padding: 26px 60px; }
.brand { font-size: 18px; font-weight: 900; letter-spacing: 0.1em; }
.nav-links { display: flex; gap: 30px; }
.nav-links a { color: #8a8077; text-decoration: none; font-size: 13px; font-weight: 700; text-transform: uppercase; letter-spacing: 0.04em; }
.nav-links a.active { color: #1e1b18; }
.hero { padding: 60px 60px 80px; max-width: 760px; }
.badge { display: inline-block; color: #a8865f; font-size: 12px; font-weight: 800; letter-spacing: 0.2em; margin-bottom: 24px; }
.hero h1 { font-size: 56px; font-weight: 800; line-height: 1.2; margin-bottom: 20px; }
.hero h1 span { color: #a8865f; }
.hero p { color: #8a8077; font-size: 16px; line-height: 1.8; max-width: 480px; }
.stats { display: grid; grid-template-columns: repeat(4, 1fr); gap: 2px; background: #1e1b18; padding: 40px 60px; }
.stat { text-align: center; color: white; padding: 10px; }
.stat strong { display: block; font-size: 32px; font-weight: 800; color: #d4b896; margin-bottom: 6px; }
.stat span { font-size: 12.5px; color: rgba(255,255,255,0.5); text-transform: uppercase; letter-spacing: 0.05em; }
.projects { padding: 70px 60px; }
.projects h2 { font-size: 30px; font-weight: 800; margin-bottom: 36px; }
.project-grid { display: grid; grid-template-columns: repeat(3, 1fr); gap: 20px; }
.project-card { cursor: pointer; }
.project-card.large { grid-column: span 2; }
.project-img { aspect-ratio: 16/10; background: linear-gradient(150deg, #e8e0d6, #d4c8b8); border-radius: 4px; display: flex; align-items: center; justify-content: center; font-size: 60px; margin-bottom: 14px; transition: 0.2s; }
.project-card.large .project-img { font-size: 90px; }
.project-card:hover .project-img { filter: brightness(0.96); }
.cat { display: block; color: #a8865f; font-size: 11px; font-weight: 800; text-transform: uppercase; letter-spacing: 0.08em; margin-bottom: 6px; }
.project-card h3 { font-size: 18px; font-weight: 700; margin-bottom: 4px; }
.loc { color: #8a8077; font-size: 13px; }
.approach { padding: 70px 60px; background: white; }
.approach h2 { font-size: 30px; font-weight: 800; margin-bottom: 36px; text-align: center; }
.approach-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(200px, 1fr)); gap: 30px; max-width: 900px; margin: 0 auto; text-align: center; }
.aicon { font-size: 36px; margin-bottom: 14px; }
.approach-item h3 { font-size: 17px; font-weight: 700; margin-bottom: 8px; }
.approach-item p { color: #8a8077; font-size: 13.5px; line-height: 1.6; }
.contact { text-align: center; padding: 90px 60px; }
.contact h2 { font-size: 34px; font-weight: 800; margin-bottom: 12px; }
.contact p { color: #8a8077; font-size: 15px; margin-bottom: 28px; }
.contact button { background: #1e1b18; color: white; border: none; padding: 16px 36px; font-size: 14px; font-weight: 700; cursor: pointer; }
.modal { position: fixed; inset: 0; background: rgba(30,27,24,0.6); display: none; align-items: center; justify-content: center; padding: 20px; z-index: 10; }
.modal.show { display: flex; }
.modal-content { background: white; border-radius: 16px; padding: 32px; max-width: 420px; width: 100%; }
.modal-img { aspect-ratio: 16/10; background: linear-gradient(150deg, #e8e0d6, #d4c8b8); border-radius: 8px; display: flex; align-items: center; justify-content: center; font-size: 70px; margin-bottom: 18px; }
.modal-content h2 { font-size: 24px; font-weight: 800; margin: 6px 0; }
.modal-content p { color: #8a8077; font-size: 14px; line-height: 1.7; margin: 16px 0 22px; }
.close-btn { background: #1e1b18; color: white; border: none; padding: 12px 28px; font-size: 14px; font-weight: 700; cursor: pointer; width: 100%; }
@media (max-width: 900px) { .navbar, .hero, .stats, .projects, .approach, .contact { padding-left: 24px; padding-right: 24px; } .nav-links { display: none; } .hero h1 { font-size: 36px; } .stats { grid-template-columns: repeat(2, 1fr); } .project-grid { grid-template-columns: 1fr; } .project-card.large { grid-column: span 1; } }

