const descriptions = {
  'Lumina Kuleleri': 'Şehrin merkezinde, sürdürülebilir malzemeler ve akıllı bina teknolojileriyle tasarlanan karma kullanım kulesi.',
  'Yeşil Vadi Evi': 'Doğayla bütünleşen, geniş cam yüzeyler ve yeşil çatı sistemiyle minimal bir tatil evi.',
  'Sanat Müzesi': 'Doğal ışığı sergi alanlarına taşıyan, modern ve heykelsi bir kültür yapısı.',
  'Sahil Resort': 'Deniz manzarasını maksimize eden, açık-kapalı mekan geçişleriyle tasarlanmış lüks resort.',
  'Kampüs Kütüphanesi': 'Öğrenciler için sosyal ve sessiz çalışma alanlarını dengeleyen modern kampüs yapısı.'
};

function openProject(el) {
  const title = el.querySelector('h3').textContent;
  const cat = el.querySelector('.cat').textContent;
  const loc = el.querySelector('.loc').textContent;
  const img = el.querySelector('.project-img').textContent;
  document.getElementById('modalImg').textContent = img;
  document.getElementById('modalCat').textContent = cat;
  document.getElementById('modalTitle').textContent = title;
  document.getElementById('modalLoc').textContent = loc;
  document.querySelector('.modal-content p').textContent = descriptions[title] || '';
  document.getElementById('modal').classList.add('show');
}

function closeModal(e) {
  if (e.target.id === 'modal' || e.target.classList.contains('close-btn')) {
    document.getElementById('modal').classList.remove('show');
  }
}

